<span class="line"><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">tidb@kafka1 </span><span style="color:#89DDFF;">~]</span><span style="color:#A6ACCD;">$  bin/kafka-server-start.sh config/server.properties</span></span>
